def curve_values(curve):
    """Coerce a single-output curve to a 1D array for tables and metrics."""
    return np.asarray(curve, dtype=float).reshape(-1)


def summarize_curve_errors(estimator_curves, truth, metric_name, metric_fn):
    """Build a sorted error summary table for a dict of estimated curves."""
    return pl.DataFrame(
        {
            "estimator": list(estimator_curves.keys()),
            metric_name: [
                float(metric_fn(predicted, truth))
                for predicted in estimator_curves.values()
            ],
        }
    ).sort(metric_name)

